"""Hidden tests for lcb-002-valid-sudoku."""
from solution import is_valid_sudoku


def test_valid_board():
    board = [
        ["5","3",".",".","7",".",".",".","."],
        ["6",".",".","1","9","5",".",".","."],
        [".","9","8",".",".",".",".","6","."],
        ["8",".",".",".","6",".",".",".","3"],
        ["4",".",".","8",".","3",".",".","1"],
        ["7",".",".",".","2",".",".",".","6"],
        [".","6",".",".",".",".","2","8","."],
        [".",".",".","4","1","9",".",".","5"],
        [".",".",".",".","8",".",".","7","9"],
    ]
    assert is_valid_sudoku(board) is True


def test_invalid_column():
    board = [
        ["8","3",".",".","7",".",".",".","."],
        ["6",".",".","1","9","5",".",".","."],
        [".","9","8",".",".",".",".","6","."],
        ["8",".",".",".","6",".",".",".","3"],
        ["4",".",".","8",".","3",".",".","1"],
        ["7",".",".",".","2",".",".",".","6"],
        [".","6",".",".",".",".","2","8","."],
        [".",".",".","4","1","9",".",".","5"],
        [".",".",".",".","8",".",".","7","9"],
    ]
    assert is_valid_sudoku(board) is False


def test_invalid_row():
    board = [
        ["5","3",".",".","7",".",".",".","5"],
        ["6",".",".","1","9","5",".",".","."],
        [".","9","8",".",".",".",".","6","."],
        ["8",".",".",".","6",".",".",".","3"],
        ["4",".",".","8",".","3",".",".","1"],
        ["7",".",".",".","2",".",".",".","6"],
        [".","6",".",".",".",".","2","8","."],
        [".",".",".","4","1","9",".",".","5"],
        [".",".",".",".","8",".",".","7","9"],
    ]
    assert is_valid_sudoku(board) is False


def test_invalid_box():
    board = [
        ["5","3",".",".","7",".",".",".","."],
        ["6",".",".","1","9","5",".",".","."],
        [".","9","5",".",".",".",".","6","."],
        ["8",".",".",".","6",".",".",".","3"],
        ["4",".",".","8",".","3",".",".","1"],
        ["7",".",".",".","2",".",".",".","6"],
        [".","6",".",".",".",".","2","8","."],
        [".",".",".","4","1","9",".",".","5"],
        [".",".",".",".","8",".",".","7","9"],
    ]
    assert is_valid_sudoku(board) is False


def test_empty_board():
    board = [["." for _ in range(9)] for _ in range(9)]
    assert is_valid_sudoku(board) is True


def test_single_entry():
    board = [["." for _ in range(9)] for _ in range(9)]
    board[0][0] = "1"
    assert is_valid_sudoku(board) is True


def test_same_digit_different_box_same_row():
    board = [["." for _ in range(9)] for _ in range(9)]
    board[0][0] = "1"
    board[0][5] = "1"  # same row, different box
    assert is_valid_sudoku(board) is False


def test_same_digit_different_row_col_box():
    board = [["." for _ in range(9)] for _ in range(9)]
    board[0][0] = "1"
    board[4][5] = "1"  # different row, col, and box
    assert is_valid_sudoku(board) is True
